import{_ as a,o as t,c as r,a2 as i}from"./chunks/framework.N9BN-Nr4.js";const g=JSON.parse('{"title":"Kingdom / BANG EDH","description":"","frontmatter":{},"headers":[],"relativePath":"formats/bang-like/sources/kingdom-bang-edh-mtgsalvation.md","filePath":"formats/bang-like/sources/kingdom-bang-edh-mtgsalvation.md","lastUpdated":1782025909000}'),l={name:"formats/bang-like/sources/kingdom-bang-edh-mtgsalvation.md"};function o(s,e,n,d,h,u){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="kingdom-bang-edh" tabindex="-1">Kingdom / BANG EDH <a class="header-anchor" href="#kingdom-bang-edh" aria-label="Permalink to &quot;Kingdom / BANG EDH&quot;">​</a></h1><p>Source: <a href="https://www.mtgsalvation.com/forums/the-game/commander-edh/616543-kingdom-aka-bang-edh-a-variant-format" target="_blank" rel="noreferrer">https://www.mtgsalvation.com/forums/the-game/commander-edh/616543-kingdom-aka-bang-edh-a-variant-format</a></p><p>Original poster: <code>kesofcom</code><br> Context: MTGSalvation Commander/EDH forum thread, July 2015.</p><p>This source presents a 5-6 player Commander variant inspired by BANG! and Three Kingdoms-style hidden-role games.</p><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><p>This is a role-playing variant used with Commander decks. Each role has its own win condition, and some roles have additional rules.</p><p>Prepare a role-card set:</p><table tabindex="0"><thead><tr><th>Role</th><th style="text-align:right;">Count</th></tr></thead><tbody><tr><td>Emperor</td><td style="text-align:right;">1</td></tr><tr><td>Guard</td><td style="text-align:right;">1</td></tr><tr><td>Assassin</td><td style="text-align:right;">2</td></tr><tr><td>Rogue</td><td style="text-align:right;">1</td></tr></tbody></table><p>For a 6-player game, add one additional Assassin.</p><p>Shuffle the role cards and deal one to each player. A player&#39;s role does not change during the game.</p><h2 id="role-visibility" tabindex="-1">Role Visibility <a class="header-anchor" href="#role-visibility" aria-label="Permalink to &quot;Role Visibility&quot;">​</a></h2><ul><li>The Emperor reveals their role.</li><li>All other roles stay secret and face down.</li><li>Roles are revealed only when a player dies or when the game ends.</li><li>Players cannot concede.</li></ul><h2 id="table-talk-rules" tabindex="-1">Table-Talk Rules <a class="header-anchor" href="#table-talk-rules" aria-label="Permalink to &quot;Table-Talk Rules&quot;">​</a></h2><p>The source is explicit that players should not use out-of-game leverage to prove their roles.</p><p>Players may not make external promises such as &quot;if I am lying, you can tear up my card.&quot;</p><p>Players also cannot talk about their role directly. They may discuss actions they have taken in the game, such as reminding another player that they destroyed a token army attacking them.</p><h2 id="role-table" tabindex="-1">Role Table <a class="header-anchor" href="#role-table" aria-label="Permalink to &quot;Role Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>Win Condition</th><th>Bonus / Penalty</th></tr></thead><tbody><tr><td>Emperor</td><td>The Emperor is alive, all Assassins are dead, and the Rogue is dead. The Guard&#39;s status does not affect the Emperor&#39;s win.</td><td>Starts first, +10 starting life, +1 starting hand size, +1 maximum hand size.</td></tr><tr><td>Guard</td><td>All Assassins are dead, the Rogue is dead, and the Emperor is not dead. The Guard can be dead and still win.</td><td>No listed bonus.</td></tr><tr><td>Assassin</td><td>The Emperor is dead, and the Rogue&#39;s win condition has not been fulfilled. Any or all Assassins can be dead and still win.</td><td>When an Assassin dies, the player who killed them may draw up to three cards.</td></tr><tr><td>Rogue</td><td>The Rogue is alive, all players except the Emperor and Rogue are alive, and the Rogue kills the Emperor.</td><td>Alternate condition: the Rogue may kill all other players at once if the Emperor is last or tied for last to die.</td></tr></tbody></table><h2 id="emperor-penalty" tabindex="-1">Emperor Penalty <a class="header-anchor" href="#emperor-penalty" aria-label="Permalink to &quot;Emperor Penalty&quot;">​</a></h2><p>If the Emperor kills the Guard, the Emperor exiles their nonland permanents, graveyard, and hand.</p><h2 id="rogue-redeal-rule" tabindex="-1">Rogue Redeal Rule <a class="header-anchor" href="#rogue-redeal-rule" aria-label="Permalink to &quot;Rogue Redeal Rule&quot;">​</a></h2><p>If a player was the Rogue in the previous game, they may request a redeal before the next game starts, until they are not the Rogue again.</p><h2 id="design-notes-from-the-thread" tabindex="-1">Design Notes From The Thread <a class="header-anchor" href="#design-notes-from-the-thread" aria-label="Permalink to &quot;Design Notes From The Thread&quot;">​</a></h2><p>The discussion focuses heavily on making the Rogue playable and preventing role-proofing.</p><p>The poster notes:</p><ul><li>A three-card reward for killing an Assassin is enough incentive without encouraging too much early killing.</li><li>The Emperor needs a meaningful penalty for killing the Guard, or the Emperor can stab blindly.</li><li>The Rogue is intentionally difficult but can be fun because it asks the player to manipulate the table.</li></ul><p>Suggested Rogue strategies include:</p><ul><li>Include a way to win in one strong turn, such as a large drain spell.</li><li>Increase spot removal and board wipes so the Rogue can help the Emperor and prolong the game.</li><li>Pretend to be the Guard, help kill the Assassins, then isolate the Emperor for the final duel.</li></ul><h2 id="alternate-rogue-discussion" tabindex="-1">Alternate Rogue Discussion <a class="header-anchor" href="#alternate-rogue-discussion" aria-label="Permalink to &quot;Alternate Rogue Discussion&quot;">​</a></h2><p>The thread discusses an alternate Rogue win condition where the Rogue wins by personally killing two players.</p><p>That creates rules complications if the Rogue&#39;s second kill is the Emperor, because the Assassin team might also be trying to win at that moment. The thread suggests avoiding simultaneous wins by ruling that:</p><ul><li>The Rogue and Assassins cannot both win if the Rogue&#39;s second kill is the Emperor; or</li><li>The Rogue&#39;s second kill cannot be the Emperor.</li></ul><h2 id="related-table-variants" tabindex="-1">Related Table Variants <a class="header-anchor" href="#related-table-variants" aria-label="Permalink to &quot;Related Table Variants&quot;">​</a></h2><p>Commenters mention simpler versions with roles such as:</p><ul><li>King</li><li>Knight</li><li>Bandits</li><li>Assassin</li></ul><p>The thread also mentions the format being known by names such as Empire and Usurper.</p><h2 id="takeaways-for-game-night-boxes" tabindex="-1">Takeaways For Game-Night Boxes <a class="header-anchor" href="#takeaways-for-game-night-boxes" aria-label="Permalink to &quot;Takeaways For Game-Night Boxes&quot;">​</a></h2><p>This version is more formal than the basic Reddit BANG! variant. It is useful if the box wants:</p><ul><li>Clear anti-role-proofing rules.</li><li>A harsh Emperor penalty.</li><li>A reward for killing Assassins.</li><li>A Rogue role with explicit strategy and balance support.</li></ul>',39)])])}const p=a(l,[["render",o]]);export{g as __pageData,p as default};
